import React, { useEffect, useMemo, useState } from "react";
import axios from "axios";
import { useNavigate, useParams } from "react-router-dom";
import { Bus, Seat } from "../types";

const API_BASE = "http://localhost:5000/api";

const SeatSelection: React.FC = () => {
  const { busId } = useParams();
  const navigate = useNavigate();

  const [bus, setBus] = useState<Bus | null>(null);
  const [selectedSeats, setSelectedSeats] = useState<number[]>([]);
  const [loading, setLoading] = useState(true);
  const [booking, setBooking] = useState(false);

  useEffect(() => {
    const fetchBus = async () => {
      if (!busId) return;
      try {
        const response = await axios.get<Bus>(`${API_BASE}/buses/${busId}`);
        setBus(response.data);
      } catch (error) {
        console.error("Failed to fetch bus", error);
      } finally {
        setLoading(false);
      }
    };

    fetchBus();
  }, [busId]);

  const seatRows = useMemo(() => {
    if (!bus) return [];
    const sorted = [...bus.seats].sort((a, b) => a.seatNumber - b.seatNumber);
    const rows: Seat[][] = [];

    for (let i = 0; i < sorted.length; i += 4) {
      rows.push(sorted.slice(i, i + 4));
    }

    return rows;
  }, [bus]);

  const totalPrice = useMemo(() => {
    if (!bus) return 0;
    return selectedSeats.length * bus.price;
  }, [bus, selectedSeats]);

  const toggleSeat = (seatNumber: number, isAvailable: boolean) => {
    if (!isAvailable) return;

    setSelectedSeats((prev) =>
      prev.includes(seatNumber) ? prev.filter((item) => item !== seatNumber) : [...prev, seatNumber]
    );
  };

  const handleBooking = async () => {
    if (!bus || !busId || selectedSeats.length === 0) return;

    setBooking(true);
    try {
      const passengerDetails = selectedSeats.map((seatNumber, index) => ({
        name: `Passenger ${index + 1}`,
        seatNumber
      }));

      const response = await axios.post(`${API_BASE}/bookings`, {
        busId,
        selectedSeats,
        passengerDetails
      });

      navigate("/confirmation", {
        state: {
          booking: response.data.booking,
          bus
        }
      });
    } catch (error) {
      console.error("Booking failed", error);
      alert("Booking failed. Please try another seat.");
    } finally {
      setBooking(false);
    }
  };

  if (loading) {
    return <p className="text-slate-600">Loading seat layout...</p>;
  }

  if (!bus) {
    return <p className="text-slate-600">Bus not found.</p>;
  }

  return (
    <section className="grid gap-6 lg:grid-cols-[2fr_1fr]">
      <div className="rounded-2xl bg-white p-6 shadow-travel ring-1 ring-slate-200">
        <div className="mb-5 border-b border-slate-200 pb-4">
          <h2 className="text-2xl font-bold text-slate-900">{bus.operatorName}</h2>
          <p className="mt-1 text-sm text-slate-600">
            {bus.departureCity} {"->"} {bus.arrivalCity}
          </p>
          <div className="mt-2 flex flex-wrap gap-x-5 gap-y-1 text-sm text-slate-600">
            <span>
              <strong>Departure:</strong> {new Date(bus.departureTime).toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" })}
            </span>
            <span>
              <strong>Arrival:</strong> {new Date(bus.arrivalTime).toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" })}
            </span>
            <span>
              <strong>Seat Type:</strong> {bus.seatType}
            </span>
            <span>
              <strong>{bus.isAC ? "AC" : "Non AC"}</strong>
            </span>
          </div>
        </div>

        <div className="mb-4 flex flex-wrap gap-4 text-xs sm:text-sm">
          <div className="flex items-center gap-2">
            <span className="h-3 w-3 rounded bg-emerald-500" />
            Available
          </div>
          <div className="flex items-center gap-2">
            <span className="h-3 w-3 rounded bg-blue-600" />
            Selected
          </div>
          <div className="flex items-center gap-2">
            <span className="h-3 w-3 rounded bg-slate-400" />
            Booked
          </div>
        </div>

        <div className="space-y-2 rounded-xl border border-slate-200 bg-slate-50 p-4">
          {seatRows.map((row, rowIndex) => (
            <div
              key={`row-${rowIndex}`}
              className="grid grid-cols-[repeat(2,minmax(0,1fr))_2.25rem_repeat(2,minmax(0,1fr))] items-center gap-2"
            >
              {row.slice(0, 2).map((seat) => {
                const isSelected = selectedSeats.includes(seat.seatNumber);
                const seatClass = !seat.isAvailable
                  ? "bg-slate-400 cursor-not-allowed"
                  : isSelected
                  ? "bg-blue-600 hover:bg-blue-700"
                  : "bg-emerald-500 hover:bg-emerald-600";

                return (
                  <button
                    key={seat.seatNumber}
                    type="button"
                    onClick={() => toggleSeat(seat.seatNumber, seat.isAvailable)}
                    className={`h-10 rounded-md text-xs font-semibold text-white shadow-sm transition sm:text-sm ${seatClass}`}
                  >
                    {seat.seatNumber}
                  </button>
                );
              })}

              <div className="h-10 rounded border border-dashed border-slate-300" />

              {row.slice(2).map((seat) => {
                const isSelected = selectedSeats.includes(seat.seatNumber);
                const seatClass = !seat.isAvailable
                  ? "bg-slate-400 cursor-not-allowed"
                  : isSelected
                  ? "bg-blue-600 hover:bg-blue-700"
                  : "bg-emerald-500 hover:bg-emerald-600";

                return (
                  <button
                    key={seat.seatNumber}
                    type="button"
                    onClick={() => toggleSeat(seat.seatNumber, seat.isAvailable)}
                    className={`h-10 rounded-md text-xs font-semibold text-white shadow-sm transition sm:text-sm ${seatClass}`}
                  >
                    {seat.seatNumber}
                  </button>
                );
              })}
            </div>
          ))}
        </div>
      </div>

      <aside className="h-fit rounded-2xl bg-white p-6 shadow-travel ring-1 ring-slate-200">
        <h3 className="text-lg font-semibold text-slate-900">Trip Summary</h3>
        <div className="mt-4 space-y-3 text-sm text-slate-700">
          <p className="flex items-center justify-between">
            <span>Price per seat</span>
            <span className="font-semibold">INR {bus.price}</span>
          </p>
          <p>
            <span className="font-medium">Selected seats:</span>{" "}
            {selectedSeats.length ? selectedSeats.join(", ") : "None"}
          </p>
          <p className="flex items-center justify-between border-t border-slate-200 pt-3 text-base font-bold text-blue-700">
            <span>Total price</span>
            <span>INR {totalPrice}</span>
          </p>
        </div>

        <button
          type="button"
          onClick={handleBooking}
          disabled={selectedSeats.length === 0 || booking}
          className="mt-5 w-full rounded-lg bg-blue-600 px-4 py-2.5 font-semibold text-white transition hover:bg-blue-700 disabled:cursor-not-allowed disabled:bg-blue-300"
        >
          {booking ? "Confirming..." : "Confirm Booking"}
        </button>
      </aside>
    </section>
  );
};

export default SeatSelection;
